function safeDivide(a: number, b: number): number | null {
  if (b === 0) {
    console.warn('Division by zero detected. Returning null instead of Infinity.');
    return null; // or handle it in a way that makes sense for your app
  }

  const result = a / b;

  if (Number.isNaN(result)) {
    console.error('Result is NaN. Please check input values.');
    return null;
  }

  if (!Number.isFinite(result)) {
    console.error('Result is Infinity. Calculation overflow or division by zero.');
    return null;
  }

  return result;
}

// Example usage:
console.log(safeDivide(10, 2)); // 5
console.log(safeDivide(10, 0)); // null with warning
console.log(safeDivide(0, 0));  // null with error

class ManagedFile:
    def __init__(self, filename):
        self.filename = filename

    def __enter__(self):
        self.file = open(self.filename, 'r')
        return self.file

    def __exit__(self, exc_type, exc_val, exc_tb):
        self.file.close()

from contextlib import contextmanager

@contextmanager
def managed_file(filename):
    f = open(filename, 'r')
    try:
        yield f
    finally:
        f.close()

def divide(x, y):
    try:
        result = x / y
    except ZeroDivisionError:
        print("Error: Cannot divide by zero.")
    else:
        print(f"Result is {result}")

# Usage
 divide(10, 2)  # Output: Result is 5.0
 divide(10, 0)  # Output: Error: Cannot divide by zero.

class NegativeNumberError(Exception):
    pass

def square_root(x):
    if x < 0:
        raise NegativeNumberError("Cannot calculate square root of a negative number.")
    return x ** 0.5

try:
    print(square_root(-4))
except NegativeNumberError as e:
    print(f"Custom error caught: {e}")

